from numpy import genfromtxt
import numpy as np
import sys
sys.path.append("../..")
import matplotlib.pyplot as plt

def change(label_show):
    length_node = len(label_show)
    lst_1 = [0] * length_node
    for i in range(0, length_node):
        lst_1[i] = str(i + 1)
    ground_truth = {}
    for v in lst_1:
        ground_truth[label_show[int(v) - 1]] = [v] if label_show[int(v) - 1] not in ground_truth else \
            ground_truth[label_show[int(v) - 1]] + [v]
    need = ground_truth
    result = []
    for key in need.keys():
        result.append([int(x) - 1 for x in need[key]])
    print(result)
    return result


